#include<bits/stdc++.h>
using namespace std;

long long ans,l,r;
struct node{
    long long s,t;
}a[20005];
bool cmp(node a,node b){
    return a.s<b.s;
}
int main(){
    int n;
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i].s>>a[i].t;
    sort(a+1,a+1+n,cmp);
     l = a[1].s;
     r =a[1].t;
     for(int i=2;i<=n;i++) {
         if(a[i].s<=r){
             r = max(r, a[i].t);
         }else{
             ans+=r-l;
             l = a[i].s;
            r = a[i].t;
         }
     }
     ans+=r-l;
    cout<<ans;
    return 0;
}
